#include<bits/stdc++.h>
#define pre(x) (x==1?n:x-1)
#define nxt(x) (x==n?1:x+1)
using namespace std;
char s[400010];
long long n,m,a[400010],ans,l,r,l1,r1,cnt1,cnt2;
int main()
{
    scanf("%lld%lld%s",&n,&m,s+1);
    for(long long i=1;i<=n;i++)
        scanf("%lld",&a[i]),ans+=a[i];
    for(long long i=1;i<=n;i++)
    {
        l=i,r=nxt(i);
        if(s[l]=='R'&&s[r]=='L')
        {
            l1=pre(l),r1=nxt(r),cnt1=0,cnt2=0;
            while(s[l1]=='R')
            {
                cnt1+=a[l1];
                l1=pre(l1);
            }
            while(s[r1]=='L')
            {
                cnt2+=a[r1];
                r1=nxt(r1);
            }
            ans-=min(m,cnt1)+min(m,cnt2);
        }
    }
    printf("%lld",ans);
    return 0;
}
